// BAD CODE — repetitive, hard to change!
void setup() {
  pinMode(3, OUTPUT);
  pinMode(5, OUTPUT);
  pinMode(6, OUTPUT);
  pinMode(9, OUTPUT);
  pinMode(11, OUTPUT);
}

void loop() {
  digitalWrite(3, HIGH); delay(500); digitalWrite(3, LOW); delay(500);
  digitalWrite(5, HIGH); delay(500); digitalWrite(5, LOW); delay(500);
  digitalWrite(6, HIGH); delay(500); digitalWrite(6, LOW); delay(500);
  digitalWrite(9, HIGH); delay(500); digitalWrite(9, LOW); delay(500);
  digitalWrite(11, HIGH); delay(500); digitalWrite(11, LOW); delay(500);
}

// CLEAN CODE — array + for-loop = magic!
int ledPins[] = {3, 5, 6, 9, 11};  // Array of LED pins
int numLEDs = 5;                    // Number of LEDs

void setup() {
  for (int i = 0; i < numLEDs; i++) {
    pinMode(ledPins[i], OUTPUT);    // Set each pin as OUTPUT
  }
}

void loop() {
  for (int i = 0; i < numLEDs; i++) {
    blinkLED(ledPins[i], 300);     // Call function for each LED
  }
}

// Function: blinks one LED a given number of ms
void blinkLED(int pin, int delayTime) {
  digitalWrite(pin, HIGH);
  delay(delayTime);
  digitalWrite(pin, LOW);
  delay(delayTime);
}

// Function that RETURNS a value
int addNumbers(int a, int b) {
  return a + b;   // sends the result back
}

// Function with parameters (inputs)
void blinkTimes(int pin, int times, int speed) {
  for (int i = 0; i < times; i++) {
    digitalWrite(pin, HIGH);
    delay(speed);
    digitalWrite(pin, LOW);
    delay(speed);
  }
}

void setup() {
  pinMode(13, OUTPUT);
  Serial.begin(9600);

  int result = addNumbers(4, 6);   // result = 10
  Serial.println(result);          // prints: 10

  blinkTimes(13, 5, 200);         // blink pin 13, 5 times, 200ms speed
}

// Nested loops: a loop inside a loop!
int ledPins[] = {3, 5, 6, 9, 11};
int numLEDs = 5;

void setup() {
  for (int i = 0; i < numLEDs; i++) {
    pinMode(ledPins[i], OUTPUT);
  }
}

void loop() {
  // Forward wave: LED 0 → 1 → 2 → 3 → 4
  for (int i = 0; i < numLEDs; i++) {
    digitalWrite(ledPins[i], HIGH);
    delay(100);
    digitalWrite(ledPins[i], LOW);
  }

  // Reverse wave: LED 4 → 3 → 2 → 1 → 0
  for (int i = numLEDs - 1; i >= 0; i--) {
    digitalWrite(ledPins[i], HIGH);
    delay(100);
    digitalWrite(ledPins[i], LOW);
  }
}
